import React, { useEffect, useState } from "react";
import api from "../api";
import { useNavigate } from "react-router-dom";

export default function FoodMenu() {
  const [foods, setFoods] = useState([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [loading, setLoading] = useState(true);
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState(searchQuery);
  const navigate = useNavigate();

  // Debounce Search Query
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearchQuery(searchQuery);
    }, 300); // Debounce delay of 300ms

    return () => clearTimeout(timer); // Cleanup timer on every render
  }, [searchQuery]);

  // Fetch Food Items
  useEffect(() => {
    const fetchFoods = async () => {
      try {
        const res = await api.get("/foods");
        setFoods(res.data);
      } catch (error) {
        console.error("Error fetching foods:", error);
        alert("Something went wrong while fetching the food list.");
      } finally {
        setLoading(false);
      }
    };
    fetchFoods();
  }, []);

  // Filter foods based on the debounced search query
  const filteredFoods = foods.filter((food) =>
    food.name.toLowerCase().includes(debouncedSearchQuery.toLowerCase())
  );

  // Navigate to Add Food page
  const addFood = () => {
    navigate("/add-item");
  };

  // Mark food item as Today's Special
  const setTodayItem = async (foodId) => {
    try {
      await api.post("/set-today-menu", { foodId });
      alert("Food marked for today!");
    } catch (error) {
      console.error("Error marking food for today:", error);
      alert("Failed to update today's menu.");
    }
  };

  // Navigate to Manage Food page (edit food details)
  const manageFood = (foodId) => {
    navigate(`/manage/${foodId}`);
  };

  // Assuming the user's role is stored somewhere, you can conditionally render buttons
  const userRole = 'admin'; // Replace with your actual user role logic (e.g., from context or state)

  return (
    <div className="container mt-5">
      <h2>Food Menu (Admin)</h2>

      {/* Search Bar */}
      <div className="d-flex justify-content-between mb-4">
        <input
          type="text"
          className="form-control w-50"
          placeholder="Search food..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
        {userRole === 'admin' && (
          <button className="btn btn-primary" onClick={addFood}>
            Add Food
          </button>
        )}
      </div>

      {/* Loading Indicator */}
      {loading ? (
        <div className="d-flex justify-content-center">
          <div className="spinner-border text-primary" role="status">
            <span className="sr-only">Loading...</span>
          </div>
        </div>
      ) : (
        <div className="row">
          {filteredFoods.map((food) => (
            <div key={food._id} className="col-md-4 mb-4">
              <div className="card">
                <img
                  src={food.image ? `http://localhost:5000/uploads/${food.image}` : '/fallback_image_url.png'} // Use full URL for local images
                  alt={food.name}
                  className="card-img-top"
                  onError={(e) => e.target.src = '/fallback_image_url.png'} // Handle error if the image URL is invalid
                />
                <div className="card-body">
                  <h5 className="card-title">{food.name}</h5>
                  <p className="card-text">{food.description}</p>

                  <div className="d-flex justify-content-between">
                    {userRole === 'admin' && (
                      <>
                        <button
                          className="btn btn-success"
                          onClick={() => setTodayItem(food._id)}
                        >
                          Mark as Today’s Item
                        </button>
                        <button
                          className="btn btn-warning"
                          onClick={() => manageFood(food._id)}
                        >
                          Manage
                        </button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
